{"content":"1: import type { FeatureId, FeatureState } from "@calcom/features/flags/config";
2: import type { FeaturesRepository } from "@calcom/features/flags/features.repository";
3: import { ErrorCode } from "@calcom/lib/errorCodes";
4: import { ErrorWithCode } from "@calcom/lib/errors";
5: 
6: import { getOptInFeatureConfig, getOptInFeaturesForScope, isFeatureAllowedForScope } from "../config";
7: import { applyAutoOptIn } from "../lib/applyAutoOptIn";
8: import { computeEffectiveStateAcrossTeams } from "../lib/computeEffectiveState";
9: import type { OptInFeaturePolicy, OptInFeatureScope } from "../types";
10: import type {
11:   EffectiveStateReason,
12:   IFeatureOptInService,
13:   ResolvedFeatureState,
14: } from "./IFeatureOptInService";
15: 
16: type ListFeaturesForUserResult = {
17:   featureId: FeatureId;
18:   globalEnabled: boolean;
19:   orgState: FeatureState;
20:   teamStates: FeatureState[];
21:   userState: FeatureState | undefined;
22:   effectiveEnabled: boolean;
23:   effectiveReason: EffectiveStateReason;
24:   orgAutoOptIn: boolean;
25:   teamAutoOptIns: boolean[];
26:   userAutoOptIn: boolean;
27: };
28: 
29: type ListFeaturesForTeamResult = {
30:   featureId: FeatureId;
31:   globalEnabled: boolean;
32:   teamState: FeatureState;
33:   orgState: FeatureState;
34: };
35: 
36: function getOrgState(orgId: number | null, teamStatesById: Record<number, FeatureState>): FeatureState {
37:   if (orgId !== null) {
38:     return teamStatesById[orgId] ?? "inherit";
39:   }
40:   return "inherit";
41: }
42: 
43: function getOrgAutoOptIn(orgId: number | null, teamsAutoOptIn: Record<number, boolean>): boolean {
44:   if (orgId !== null) {
45:     return teamsAutoOptIn[orgId] ?? false;
46:   }
47:   return false;
48: }
49: 
50: function getTeamIdsToQuery(teamId: number, parentOrgId: number | null | undefined): number[] {
51:   if (parentOrgId) {
52:     return [teamId, parentOrgId];
53:   }
54:   return [teamId];
55: }
56: 
57: function getOrgStateForTeam(
58:   parentOrgId: number | null | undefined,
59:   teamStates: Record<string, Record<number, FeatureState>>,
60:   slug: FeatureId
61: ): FeatureState {
62:   if (parentOrgId) {
63:     return teamStates[slug]?.[parentOrgId] ?? "inherit";
64:   }
65:   return "inherit";
66: }
67: 
68: /**
69:  * Service class for managing feature opt-in logic.
70:  * Computes effective states based on global, org, team, and user settings.
71:  */
72: export class FeatureOptInService implements IFeatureOptInService {
73:   constructor(private featuresRepository: FeaturesRepository) {}
74: 
75:   /**
76:    * Core method: Resolve feature states for a user across all their teams.
77:    *
78:    * Precedence rules:
79:    * 1. Global disabled → false (stop)
80:    * 2. Org explicitly disabled → false (stop)
81:    * 3. Org explicitly enabled → allowed at org level, continue to teams
82:    * 4. Org inherits (or no org) → check teams
83:    * 5. All teams explicitly disabled → false (stop)
84:    * 6. At least one team enabled OR inherits → allowed at team level, continue to user
85:    * 7. User explicitly disabled → false
86:    * 8. User explicitly enabled OR inherits → true
87:    *
88:    * Auto-opt-in transformation:
89:    * - If autoOptInFeatures=true at a level AND state is "inherit", transform to "enabled"
90:    * - This transformation happens before computing effectiveEnabled
91:    */
92:   async resolveFeatureStatesAcrossTeams({
93:     userId,
94:     orgId,
95:     teamIds,
96:     featureIds,
97:   }: {
98:     userId: number;
99:     orgId: number | null;
100:     teamIds: number[];
101:     featureIds: FeatureId[];
102:   }): Promise<Record<string, ResolvedFeatureState>> {
103:     const allTeamIds = orgId !== null ? [orgId, ...teamIds] : teamIds;
104: 
105:     const [allFeatures, allTeamStates, userStates, userAutoOptIn, teamsAutoOptIn] = await Promise.all([
106:       this.featuresRepository.getAllFeatures(),
107:       this.featuresRepository.getTeamsFeatureStates({ teamIds: allTeamIds, featureIds }),
108:       this.featuresRepository.getUserFeatureStates({ userId, featureIds }),
109:       this.featuresRepository.getUserAutoOptIn(userId),
110:       this.featuresRepository.getTeamsAutoOptIn(allTeamIds),
111:     ]);
112: 
113:     const globalEnabledMap = new Map(allFeatures.map((feature) => [feature.slug, feature.enabled ?? false]));
114:     const resolvedStates: Record<string, ResolvedFeatureState> = {};
115: 
116:     for (const featureId of featureIds) {
117:       const state = this.resolveFeatureState(
118:         featureId,
119:         orgId,
120:         teamIds,
121:         globalEnabledMap,
122:         allTeamStates,
123:         userStates,
124:         teamsAutoOptIn,
125:         userAutoOptIn
126:       );
127:       resolvedStates[featureId] = state;
128:     }
129: 
130:     return resolvedStates;
131:   }
132: 
133:   private resolveFeatureState(
134:     featureId: FeatureId,
135:     orgId: number | null,
136:     teamIds: number[],
137:     globalEnabledMap: Map<string, boolean>,
138:     allTeamStates: Record<string, Record<number, FeatureState>>,
139:     userStates: Record<string, FeatureState>,
140:     teamsAutoOptIn: Record<number, boolean>,
141:     userAutoOptIn: boolean
142:   ): ResolvedFeatureState {
143:     const globalEnabled = globalEnabledMap.get(featureId) ?? false;
144:     const teamStatesById = allTeamStates[featureId] ?? {};
145: 
146:     const orgState = getOrgState(orgId, teamStatesById);
147:     const teamStates = teamIds.map((teamId) => teamStatesById[teamId] ?? "inherit");
148:     const userState = userStates[featureId] ?? "inherit";
149:     const orgAutoOptIn = getOrgAutoOptIn(orgId, teamsAutoOptIn);
150:     const teamAutoOptIns = teamIds.map((teamId) => teamsAutoOptIn[teamId] ?? false);
151: 
152:     const { effectiveOrgState, effectiveTeamStates, effectiveUserState } = applyAutoOptIn({
153:       orgState,
154:       teamStates,
155:       userState,
156:       orgAutoOptIn,
157:       teamAutoOptIns,
158:       userAutoOptIn,
159:     });
160: 
161:     // Get the policy for this feature from the config
162:     const featureConfig = getOptInFeatureConfig(featureId);
163:     const policy: OptInFeaturePolicy = featureConfig?.policy ?? "permissive";
164: 
165:     const { enabled: effectiveEnabled, reason: effectiveReason } = computeEffectiveStateAcrossTeams({
166:       globalEnabled,
167:       orgState: effectiveOrgState,
168:       teamStates: effectiveTeamStates,
169:       userState: effectiveUserState,
170:       policy,
171:     });
172: 
173:     return {
174:       featureId,
175:       globalEnabled,
176:       orgState,
177:       teamStates,
178:       userState,
179:       effectiveEnabled,
180:       effectiveReason,
181:       orgAutoOptIn,
182:       teamAutoOptIns,
183:       userAutoOptIn,
184:     };
185:   }
186: 
187:   /**
188:    * List all opt-in features with their states for a user across teams.
189:    * Only returns features that are in the allowlist, globally enabled, and scoped to "user".
190:    */
191:   async listFeaturesForUser(input: {
192:     userId: number;
193:     orgId: number | null;
194:     teamIds: number[];
195:   }): Promise<ListFeaturesForUserResult[]> {
196:     const { userId, orgId, teamIds } = input;
197:     const userScopedFeatures = getOptInFeaturesForScope("user");
198:     const featureIds = userScopedFeatures.map((config) => config.slug);
199: 
200:     const resolvedStates = await this.resolveFeatureStatesAcrossTeams({
201:       userId,
202:       orgId,
203:       teamIds,
204:       featureIds,
205:     });
206: 
207:     return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => state.globalEnabled);
208:   }
209: 
210:   /**
211:    * List all opt-in features with their raw states for a team or organization.
212:    * Used for team/org admin settings page to configure feature opt-in.
213:    * Only returns features that are in the allowlist, globally enabled, and scoped to the specified scope.
214:    * If parentOrgId is provided, also returns the organization state for each feature.
215:    */
216:   async listFeaturesForTeam(input: {
217:     teamId: number;
218:     parentOrgId?: number | null;
219:     scope?: OptInFeatureScope;
220:   }): Promise<ListFeaturesForTeamResult[]> {
221:     const { teamId, parentOrgId, scope = "team" } = input;
222:     const teamIdsToQuery = getTeamIdsToQuery(teamId, parentOrgId);
223:     const scopedFeatures = getOptInFeaturesForScope(scope);
224: 
225:     const [allFeatures, teamStates] = await Promise.all([
226:       this.featuresRepository.getAllFeatures(),
227:       this.featuresRepository.getTeamsFeatureStates({
228:         teamIds: teamIdsToQuery,
229:         featureIds: scopedFeatures.map((config) => config.slug),
230:       }),
231:     ]);
232: 
233:     const results = scopedFeatures.map((config) => {
234:       const globalFeature = allFeatures.find((f) => f.slug === config.slug);
235:       const globalEnabled = globalFeature?.enabled ?? false;
236:       const teamState = teamStates[config.slug]?.[teamId] ?? "inherit";
237:       const orgState = getOrgStateForTeam(parentOrgId, teamStates, config.slug);
238: 
239:       return { featureId: config.slug, globalEnabled, teamState, orgState };
240:     });
241: 
242:     return results.filter((result) => result.globalEnabled);
243:   }
244: 
245:   /**
246:    * Set user's feature state.
247:    * Delegates to FeaturesRepository.setUserFeatureState.
248:    * Throws an error if the feature is not scoped to "user".
249:    */
250:   async setUserFeatureState(
251:     input:
252:       | { userId: number; featureId: FeatureId; state: "enabled" | "disabled"; assignedBy: number }
253:       | { userId: number; featureId: FeatureId; state: "inherit" }
254:   ): Promise<void> {
255:     const { userId, featureId, state } = input;
256: 
257:     if (!isFeatureAllowedForScope(featureId, "user")) {
258:       throw new ErrorWithCode(
259:         ErrorCode.BadRequest,
260:         `Feature "${featureId}" is not available at the user scope`
261:       );
262:     }
263: 
264:     if (state === "inherit") {
265:       await this.featuresRepository.setUserFeatureState({ userId, featureId, state });
266:     } else {
267:       const { assignedBy } = input;
268:       await this.featuresRepository.setUserFeatureState({
269:         userId,
270:         featureId,
271:         state,
272:         assignedBy: `user-${assignedBy}`,
273:       });
274:     }
275:   }
276: 
277:   /**
278:    * Set team's feature state.
279:    * Delegates to FeaturesRepository.setTeamFeatureState.
280:    * Throws an error if the feature is not scoped to the specified scope.
281:    */
282:   async setTeamFeatureState(
283:     input:
284:       | { teamId: number; featureId: FeatureId; state: "enabled" | "disabled"; assignedBy: number; scope?: OptInFeatureScope }
285:       | { teamId: number; featureId: FeatureId; state: "inherit"; scope?: OptInFeatureScope }
286:   ): Promise<void> {
287:     const { teamId, featureId, state } = input;
288:     const scope = input.scope ?? "team";
289: 
290:     if (!isFeatureAllowedForScope(featureId, scope)) {
291:       throw new ErrorWithCode(
292:         ErrorCode.BadRequest,
293:         `Feature "${featureId}" is not available at the ${scope} scope`
294:       );
295:     }
296: 
297:     if (state === "inherit") {
298:       await this.featuresRepository.setTeamFeatureState({ teamId, featureId, state });
299:     } else {
300:       const { assignedBy } = input;
301:       await this.featuresRepository.setTeamFeatureState({
302:         teamId,
303:         featureId,
304:         state,
305:         assignedBy: `user-${assignedBy}`,
306:       });
307:     }
308:   }
309: }
